7	    it("should return premium 5 for an empty item list (processing fee only)", () => {
8	      const result = runScenario({
9	        customer: { yearsWithMHPCO: 0 },
10	        steps: [{ op: "quote", items: [] }],
11	      });
12	
13	      expect(result.results[0].premium).toBe(5);
14	    });
15	    it("should quote a single sword at base premium 100 (plus first-insurance surcharge and fee)", () => {
16	      const result = runScenario({
17	        customer: { yearsWithMHPCO: 0 },
18	        steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	      });
20	
21	      expect(result.results[0].premium).toBe(115);
22	    });
23	    it.todo("should use base premiums amulet 60, staff 80, potion 40");
24	    it.todo("should charge 25 per component: 2 runes give base premium 50");
25	    it.todo("should apply the block premium 60 for exactly 3 alike components: 3 runes give base premium 60");
26	    it.todo("should not apply the block to 4 alike components: 4 runes give base premium 100");
27	    it.todo("should price 7 runes at base premium 175");
28	    it.todo("should not form a block from different component types: 2 runes + 1 moonstone give base premium 75");
29	    it.todo("should form one block per component type: 3 runes + 3 moonstones give base premium 120");
30	    it.todo("should add 50% of the item base premium for a cursed item");
31	    it.todo("should add 30% of the item base premium for enchantment level exactly 5");
32	    it.todo("should not add the enchantment surcharge for enchantment level 4");
33	    it.todo("should stack curse and enchantment surcharges on one item");
34	    it.todo("should apply the cursed surcharge only to the cursed item's base premium: cursed sword + plain amulet give 210 before policy modifiers and fee");
35	    it.todo("should apply the 20% loyalty discount for yearsWithMHPCO exactly 2");
36	    it.todo("should apply the 10% first-insurance surcharge to every quote");
37	    it.todo("should apply the 15% follow-up discount to each quote after the first");
38	    it.todo("should round the final premium up to whole gold (197.5 becomes 198)");
39	    it.todo("should quote 165 for a newcomer (0 years) with a cursed steel sword of enchantment 3");
