42	
43	  describe("Claim payout", () => {
44	    it.todo("should subtract the 100 deductible from the damage amount: regular sword (enchantment 3) damaged 500 pays out 400");
45	    it.todo("should apply the deductible per damaged item, not per incident: sword 500 + amulet 300 pay out 600");
