49	    it.todo("should treat components as having no enchantment or material: rune damaged 200 pays out 100");
50	    it.todo("should return remainingCap as 2x the insurance sum minus payouts: sword + amulet have insurance sum 1600 and cap 3200");
51	    it.todo("should keep the insurance sum unmodified by the block discount: sword + 3 runes have insurance sum 1750");
52	    it.todo("should sum same-type items into the insurance sum: two swords have insurance sum 2000 and cap 4000");
53	    it.todo("should consume the cap across successive claims: sword (cap 2000) with two claims of 1500 pays 1400 then 600");
54	    it.todo("should round the final payout down to whole gold (350.5 becomes 350)");
55	    it.todo("should apply a separate deductible per damage entry for two insured swords");
