57	
58	  describe("Errors", () => {
59	    it.todo("should reject a quote containing an unknown item type (broomstick)");
60	    it.todo("should reject a claim damage entry whose item type is not in the policy (amulet damaged, only sword insured)");
61	    it.todo("should reject a claim with more damage entries of a type than items insured (two sword damages, one sword insured)");
62	    it.todo("should reject a claim damage entry with an unknown item type");
63	    it.todo("should reject a negative damage amount");
